use strict;
use warnings;
use CGI qw(:standard);
use Storable qw(nstore retrieve);

# Create a new session or retrieve existing one
sub handle_session {
    my $cgi = CGI->new();
    my $session_id = param('session_id') || generate_session_id();

    # Load session data from file
    my $session_data;
    if (-e "/tmp/sess_$session_id") {
        $session_data = retrieve("/tmp/sess_$session_id");
    } else {
        $session_data = {};
    }

    # Update session data (example: increment a counter)
    $session_data->{counter} //= 0;
    $session_data->{counter}++;

    # Save session data back to file
    nstore($session_data, "/tmp/sess_$session_id");

    # Set the session ID cookie
    print header(-cookie => [
        -name    => 'session_id',
        -value   => $session_id,
        -expires => '+1h',  # Session expires in 1 hour
        -path    => '/'
    ]);

    # Return session data (example: display counter)
    print start_html("Session Data");
    print "Counter: ", $session_data->{counter}, "<br>";
    print end_html();
}

# Generate a new unique session ID
sub generate_session_id {
    return join('', ('A'..'Z', 'a'..'z', '0'..'9')[(rand 62) for 1..16]);
}

handle_session();